11|        $theme_env_line = trim($theme_env_line);
12|        if ($theme_env_line === '' || $theme_env_line[0] === '#') {
13|            continue;
14|        }
15|        if (strpos($theme_env_line, '=') === false) {
16|            continue;
17|        }
18|        list($key, $value) = explode('=', $theme_env_line, 2);
19|        $key = trim($key);
20|        $value = trim($value);
21|        if (preg_match('/^([\'"])(.*)\1$/', $value, $matches)) {
22|            $value = $matches[2];
23|        }
24|        if (!defined($key)) {
25|            define($key, $value);
26|        }
27|    }
