204|.hero-anim-portrait { animation: hero-portrait 1100ms cubic-bezier(0.2, 0.7, 0.2, 1) both; }
205|.hero-anim-rule     { animation: hero-rule 800ms cubic-bezier(0.7, 0, 0.2, 1) both; transform-origin: left center; }
